import React, { useRef, useState } from 'react';
import './App.css';
import firebase from 'firebase/app';
import 'firebase/firestore';
import 'firebase/auth';
import { useAuthState } from 'react-firebase-hooks/auth';
import { useCollectionData } from 'react-firebase-hooks/firestore';

firebase.initializeApp({
  apiKey: "AIzaSyChrfsHBeDKy56koXEFCPgOPM9f_BJh9Rk",
  authDomain: "chat-65f4a.firebaseapp.com",
  projectId: "chat-65f4a",
  storageBucket: "chat-65f4a.firebasestorage.app",
  messagingSenderId: "512709701751",
  appId: "1:512709701751:web:9f1d34aae5a67aee451672"
});

const auth = firebase.auth();
const firestore = firebase.firestore();

function App() {
  const [user] = useAuthState(auth);
  const [channel, setChannel] = useState('general');

  return (
    <div className="App">
      {user ? <ChatRoom channel={channel} setChannel={setChannel} /> : <AuthScreen />}
    </div>
  );
}

function AuthScreen() {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleEmailAuth = async (e) => {
    e.preventDefault();
    setError('');
    try {
      if (isLogin) {
        await auth.signInWithEmailAndPassword(email, password);
      } else {
        await auth.createUserWithEmailAndPassword(email, password);
      }
    } catch (err) {
      setError(err.message);
    }
  };

  const signInWithGoogle = () => {
    const provider = new firebase.auth.GoogleAuthProvider();
    auth.signInWithPopup(provider);
  };

  return (
    <div className="signin-container" style={{flexDirection: 'column', gap: '20px'}}>
      <div style={{background: '#2f3136', padding: '30px', borderRadius: '12px', width: '300px', boxShadow: '0 8px 24px rgba(0,0,0,0.2)'}}>
        <h2 style={{marginTop: 0, textAlign: 'center'}}>{isLogin ? 'Welcome Back' : 'Create an Account'}</h2>
        <form onSubmit={handleEmailAuth} style={{display: 'flex', flexDirection: 'column', gap: '15px', padding: 0}}>
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <input type="password" placeholder="Password (min 6 chars)" value={password} onChange={(e) => setPassword(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <button type="submit" className="sign-in">{isLogin ? 'Login' : 'Sign Up'}</button>
        </form>
        {error && <p style={{color: '#ed4245', fontSize: '12px', textAlign: 'center'}}>{error}</p>}
        <p style={{textAlign: 'center', fontSize: '13px', cursor: 'pointer', color: '#00aff4'}} onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Need an account? Register' : 'Already have an account? Login'}
        </p>
        <hr style={{borderColor: '#202225', margin: '20px 0'}} />
        <button className="sign-in" style={{width: '100%', backgroundColor: '#fff', color: '#000'}} onClick={signInWithGoogle}>Continue with Google</button>
      </div>
    </div>
  );
}

function SettingsModal({ close }) {
  const [name, setName] = useState(auth.currentUser.displayName || '');
  const [photo, setPhoto] = useState(auth.currentUser.photoURL || '');

  const saveSettings = async () => {
    await auth.currentUser.updateProfile({ displayName: name, photoURL: photo });
    close();
  };

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>User Settings</h2>
        <input placeholder="Display Name" value={name} onChange={(e) => setName(e.target.value)} />
        <input placeholder="Profile Image URL" value={photo} onChange={(e) => setPhoto(e.target.value)} />
        <div className="modal-actions">
          <button className="btn-secondary" onClick={close}>Cancel</button>
          <button className="sign-in" onClick={saveSettings}>Save</button>
        </div>
      </div>
    </div>
  );
}

function ChatRoom({ channel, setChannel }) {
  const dummy = useRef();
  const messagesRef = firestore.collection(channel);
  const query = messagesRef.orderBy('createdAt').limit(50);
  const [messages] = useCollectionData(query, { idField: 'id' });
  const [formValue, setFormValue] = useState('');
  const [showSettings, setShowSettings] = useState(false);

  // ADMIN CHECK
  const isAdmin = auth.currentUser?.email === 'vincentr111222@gmail.com';

  const sendMessage = async (e) => {
    e.preventDefault();
    if (!formValue.trim()) return;
    const { uid, photoURL, displayName, email } = auth.currentUser;
    await messagesRef.add({
      text: formValue,
      createdAt: firebase.firestore.FieldValue.serverTimestamp(),
      uid,
      email: email || '',
      photoURL: photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png',
      displayName: displayName || email?.split('@')[0] || 'Anonymous'
    });
    setFormValue('');
    dummy.current.scrollIntoView({ behavior: 'smooth' });
  }

  const deleteMessage = async (id) => {
    await messagesRef.doc(id).delete();
  }

  return (
    <div className="discord-layout">
      {showSettings && <SettingsModal close={() => setShowSettings(false)} />}
      <div className="sidebar">
        <div className="server-icon active">T</div>
      </div>
      
      <div className="channels">
        <h3>Text Channels</h3>
        <div className={`channel ${channel === 'general' ? 'active' : ''}`} onClick={() => setChannel('general')}><span className="hash-icon">#</span> general</div>
        <div className={`channel ${channel === 'gaming' ? 'active' : ''}`} onClick={() => setChannel('gaming')}><span className="hash-icon">#</span> gaming</div>
        <div className={`channel ${channel === 'memes' ? 'active' : ''}`} onClick={() => setChannel('memes')}><span className="hash-icon">#</span> memes</div>
        
        <div className="user-panel">
          <button className="btn-secondary" onClick={() => setShowSettings(true)}>⚙️ Settings</button>
          {auth.currentUser && <button className="sign-out" onClick={() => auth.signOut()}>Log Out</button>}
        </div>
      </div>

      <div className="chat-container">
        <header>
          <div className="header-title"><span className="hash-icon">#</span> {channel}</div>
        </header>

        <main>
          {messages && messages.map(msg => (
            <ChatMessage key={msg.id} message={msg} currentUserUid={auth.currentUser.uid} isAdmin={isAdmin} onDelete={() => deleteMessage(msg.id)} />
          ))}
          <span ref={dummy}></span>
        </main>

        <form onSubmit={sendMessage}>
          <input value={formValue} onChange={(e) => setFormValue(e.target.value)} placeholder={`Message #${channel}`} />
        </form>
      </div>
    </div>
  )
}

function ChatMessage({ message, currentUserUid, isAdmin, onDelete }) {
  const { text, photoURL, displayName, uid, email } = message;
  
  // Can delete if they wrote it, OR if the current logged-in user is the Admin
  const canDelete = uid === currentUserUid || isAdmin;
  const isMessageFromAdmin = email === 'vincentr111222@gmail.com';

  return (
    <div className="message" style={{justifyContent: 'space-between'}}>
      <div style={{display: 'flex'}}>
        <img src={photoURL} alt="user" />
        <div className="message-content">
          <span className="msg-author">
            {displayName}
            {isMessageFromAdmin && <span className="admin-badge">Admin</span>}
          </span>
          <p>{text}</p>
        </div>
      </div>
      {canDelete && (
        <button onClick={onDelete} style={{background: 'transparent', border: 'none', color: '#ed4245', cursor: 'pointer', opacity: 0.7}}>Delete</button>
      )}
    </div>
  )
}
export default App;
